        <Slider Value="{Binding Temperature}"
                Minimum="0"
                Maximum="100" />
    </StackLayout>
</ContentPage>
```

This custom gauge demonstrates all the key concepts: interface definition, platform view implementation, property mapping, and handler registration.

Building robust handlers requires understanding common patterns and avoiding frequent mistakes. Here are battle-tested practices from the OpenMaui.Controls.Linux codebase.

## Best Practices

### 1. Always Unsubscribe Events

The most common memory leak source is forgetting to unsubscribe events:

```csharp
// ❌ BAD: Memory leak
protected override void ConnectHandler(SkiaButton platformView)
{
    platformView.Clicked += OnClicked;
}

// ✅ GOOD: Proper cleanup
protected override void ConnectHandler(SkiaButton platformView)
{
    base.ConnectHandler(platformView);
    platformView.Clicked += OnClicked;
}

protected override void DisconnectHandler(SkiaButton platformView)
{
    platformView.Clicked -= OnClicked;
    base.DisconnectHandler(platformView);
}
```

### 2. Null-Check Platform Views

Property mappers can be called before the platform view is created:

```csharp
// ❌ BAD: Potential NullReferenceException
private static void MapText(ButtonHandler handler, IButton button)
{
    handler.PlatformView.Text = button.Text;
}

// ✅ GOOD: Defensive null check
private static void MapText(ButtonHandler handler, IButton button)
{
    handler.PlatformView?.UpdateText(button.Text);
}
```

### 3. Use Extension Methods for Platform Updates

Extension methods keep mappers clean and testable:

```csharp
// ✅ GOOD: Clean mapper with extension method
private static void MapText(ButtonHandler handler, IButton button)
{
    handler.PlatformView?.UpdateText(button.Text);
}

public static void UpdateText(this SkiaButton button, string? text)
{
    if (button.Text == text) return; // Avoid unnecessary updates

    button.Text = text ?? string.Empty;
    button.Invalidate();
}
```

### 4. Batch Property Updates

When multiple properties change, batch invalidation calls:

```csharp
public static void UpdateFont(this SkiaLabel label, Font font)
{
    label.BeginUpdate();

    try
    {
        label.FontFamily = font.Family;
        label.FontSize = (float)font.Size;
        label.FontWeight = MapFontWeight(font.Weight);
    }
    finally
    {
        label.EndUpdate(); // Single invalidation
    }
}
```

### 5. Implement Proper Disposal

Always dispose SkiaSharp resources:

```csharp
public class SkiaImage : SkiaView, IDisposable
{
    private SKBitmap? _bitmap;
    private bool _disposed;

    protected override void Dispose(bool disposing)
    {
        if (_disposed) return;

        if (disposing)
        {
            _bitmap?.Dispose();
            _bitmap = null;
        }

        _disposed = true;
        base.Dispose(disposing);
    }
}
```

### 6. Use Weak Event Handlers for Long-Lived Subscriptions

For event sources that outlive the handler, use weak references:

```csharp
public class ThemeHandler
{
    private readonly WeakEventManager _weakEventManager = new();

    public void ConnectHandler()
    {
        // Theme service outlives individual handlers
        _weakEventManager.AddEventHandler<ThemeChangedEventArgs>(
            ThemeService.Instance,
            nameof(ThemeService.ThemeChanged),
            OnThemeChanged
        );
    }

    public void DisconnectHandler()
    {
        _weakEventManager.RemoveEventHandler<ThemeChangedEventArgs>(
            ThemeService.Instance,
            nameof(ThemeService.ThemeChanged),
            OnThemeChanged
        );
    }
}
```

### 7. Validate Property Values

Use coercion callbacks to validate property values:

```csharp
public static readonly BindableProperty ValueProperty = 
    BindableProperty.Create(
        nameof(Value),
        typeof(double),
        typeof(Gauge),
        0.0,
        coerceValue: CoerceValue);

private static object CoerceValue(BindableObject bindable, object value)
{
    var gauge = (Gauge)bindable;
    var doubleValue = (double)value;

    // Clamp value between min and max
    return Math.Max(gauge.Minimum, Math.Min(gauge.Maximum, doubleValue));
}
```

## Common Pitfalls

### Pitfall 1: Forgetting Base Class Calls

```csharp
// ❌ BAD: Skips base initialization
protected override void ConnectHandler(SkiaButton platformView)
{
    platformView.Clicked += OnClicked;
}

// ✅ GOOD: Calls base first
protected override void ConnectHandler(SkiaButton platformView)
{
    base.ConnectHandler(platformView); // CRITICAL
    platformView.Clicked += OnClicked;
}
```

### Pitfall 2: Circular Property Updates

Two-way binding can cause infinite loops:

```csharp
// ❌ BAD: Causes infinite loop
private void OnTextChanged(object? sender, TextChangedEventArgs e)
{
    VirtualView.Text = e.NewTextValue; // Triggers mapper
}

private static void MapText(EntryHandler handler, IEntry entry)
{
    handler.PlatformView.Text = entry.Text; // Triggers TextChanged
}

// ✅ GOOD: Check for actual changes
private void OnTextChanged(object? sender, TextChangedEventArgs e)
{
    if (VirtualView.Text != e.NewTextValue)
    {
        VirtualView.Text = e.NewTextValue;
    }
}

private static void MapText(EntryHandler handler, IEntry entry)
{
    if (handler.PlatformView.Text != entry.Text)
    {
        handler.PlatformView.Text = entry.Text;
    }
}
```

### Pitfall 3: Ignoring Thread Safety

```csharp
// ❌ BAD: Updates UI from background thread
private async Task LoadImageAsync(string url)
{
    var bitmap = await DownloadImageAsync(url);
    PlatformView.Bitmap = bitmap; // May be called on background thread
}

// ✅ GOOD: Dispatches to UI thread
private async Task LoadImageAsync(string url)
{
    var bitmap = await DownloadImageAsync(url);

    await Dispatcher.DispatchAsync(() =>
    {
        PlatformView.Bitmap = bitmap;
    });
}
```

### Pitfall 4: Premature Optimization

```csharp
// ❌ BAD: Complex caching before profiling
private static readonly ConcurrentDictionary<string, SKTypeface> _typefaceCache = new();

private static void MapFont(LabelHandler handler, ILabel label)
{
    var key = $"{label.FontFamily}_{label.FontSize}_{label.FontAttributes}";
    var typeface = _typefaceCache.GetOrAdd(key, _ => CreateTypeface(label));
    handler.PlatformView.Typeface = typeface;
}

// ✅ GOOD: Simple implementation first, optimize if needed
private static void MapFont(LabelHandler handler, ILabel label)
{
    var typeface = CreateTypeface(label);
    handler.PlatformView.Typeface = typeface;
}
```

Profile before optimizing. OpenMaui's `TextRenderCache` was added only after profiling showed text shaping was a bottleneck.

### Pitfall 5: Tight Coupling to Platform Implementation

```csharp
// ❌ BAD: Handler knows too much about platform internals
private static void MapText(ButtonHandler handler, IButton button)
{
    var skiaButton = handler.PlatformView;
    skiaButton._textPaint.Color = button.TextColor.ToSKColor();
    skiaButton._textPaint.TextSize = (float)button.FontSize;
    skiaButton.QueueDraw();
}

// ✅ GOOD: Uses platform view's public API
private static void MapText(ButtonHandler handler, IButton button)
{
    handler.PlatformView?.UpdateText(button.Text);
}
```

Keep handlers focused on mapping, not implementation details.

## Testing Handlers

OpenMaui includes comprehensive handler tests:

```csharp
public class ButtonHandlerTests
{
    [Fact]
    public void MapText_UpdatesPlatformView()
    {
        // Arrange
        var button = new Button { Text = "Click Me" };
        var handler = new ButtonHandler();
        handler.SetVirtualView(button);
        var platformView = handler.CreatePlatformView();
        handler.SetPlatformView(platformView);

        // Act
        ButtonHandler.MapText(handler, button);

        // Assert
        platformView.Text.Should().Be("Click Me");
    }

    [Fact]
    public void Clicked_RaisesVirtualViewEvent()
    {
        // Arrange
        var button = new Button();
        var handler = new ButtonHandler();
        handler.SetVirtualView(button);
        var platformView = handler.CreatePlatformView();
        handler.SetPlatformView(platformView);
        handler.ConnectHandler(platformView);

        var eventRaised = false;
        button.Clicked += (s, e) => eventRaised = true;

        // Act
        platformView.SimulateClick();

        // Assert
        eventRaised.Should().BeTrue();
    }

    [Fact]
    public void DisconnectHandler_UnsubscribesEvents()
    {
        // Arrange
        var button = new Button();
        var handler = new ButtonHandler();
        handler.SetVirtualView(button);
        var platformView = handler.CreatePlatformView();
        handler.ConnectHandler(platformView);

        // Act
        handler.DisconnectHandler(platformView);

        var eventRaised = false;
        button.Clicked += (s, e) => eventRaised = true;
        platformView.SimulateClick();

        // Assert
        eventRaised.Should().BeFalse();
    }
}
```

## Performance Tips

1. **Profile Before Optimizing**: Use OpenMaui's built-in performance benchmarks to identify bottlenecks
2. **Cache Expensive Resources**: Typefaces, bitmaps, and shaped text benefit from caching
3. **Use Dirty Region Tracking**: Only redraw changed areas, not the entire view
4. **Batch Updates**: Group property changes to minimize invalidation calls
5. **Virtualize Collections**: Use `CollectionView` with recycling for large datasets
6. **Enable GPU Acceleration**: OpenMaui defaults to hardware rendering—ensure it's enabled
7. **Minimize Allocations**: Reuse SKPaint objects and avoid creating new objects in draw loops

By following these practices and avoiding common pitfalls, you'll create handlers that are performant, maintainable, and leak-free—essential qualities for production MAUI applications on Linux.
